# Temporal workflow — the durable execution equivalent of the above agent

from temporalio import activity, workflow
from temporalio.client import Client
from temporalio.worker import Worker
import anthropic

# Activities = side-effectful steps (LLM calls, DB writes, HTTP requests)
@activity.defn
async def generate_outline(topic: str) -> str:
    client = anthropic.Anthropic()
    return client.messages.create(
        model="claude-sonnet-5",
        max_tokens=1000,
        messages=[{"role": "user", "content": f"Create a 10-section outline for: {topic}"}],
    ).content[0].text

@activity.defn
async def generate_section(section_title: str, index: int) -> str:
    client = anthropic.Anthropic()
    return client.messages.create(
        model="claude-haiku-4-5-20251001",  # cheaper model for individual sections
        max_tokens=500,
        messages=[{"role": "user", "content": f"Write section {index+1}: {section_title}"}],
    ).content[0].text

# Workflow = orchestration logic (pure, deterministic, replayable)
@workflow.defn
class ResearchWorkflow:
    @workflow.run
    async def run(self, topic: str) -> str:
        outline = await workflow.execute_activity(
            generate_outline,
            topic,
            schedule_to_close_timeout=timedelta(seconds=120),
        )
        sections = []
        for i, section in enumerate(outline.split("\n")[:10]):
            # If the worker crashes here, Temporal resumes from the last
            # completed activity — generate_outline is NOT called again.
            content = await workflow.execute_activity(
                generate_section,
                args=[section, i],
                schedule_to_close_timeout=timedelta(seconds=60),
            )
            sections.append(content)
        return "\n\n".join(sections)

from temporalio import workflow

@workflow.defn
class LongResearchWorkflow:
    def __init__(self):
        self._paused   = False
        self._sections = []

    # Signal: external caller can pause/resume the workflow at any time
    @workflow.signal
    async def pause(self):
        self._paused = True

    @workflow.signal
    async def resume(self):
        self._paused = False

    # Query: caller can read current state without affecting the workflow
    @workflow.query
    def sections_completed(self) -> int:
        return len(self._sections)

    @workflow.run
    async def run(self, topic: str) -> str:
        outline = await workflow.execute_activity(
            generate_outline, topic,
            schedule_to_close_timeout=timedelta(seconds=120),
        )
        for i, section in enumerate(outline.split("\n")[:10]):
            # Honour pause signal — wait until resumed
            await workflow.wait_condition(lambda: not self._paused)
            content = await workflow.execute_activity(
                generate_section, args=[section, i],
                schedule_to_close_timeout=timedelta(seconds=60),
            )
            self._sections.append(content)
        return "\n\n".join(self._sections)
